)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota")

// PolicyQuotaController enforces per-namespace limits on the number of
// CiliumNetworkPolicy resources.
type PolicyQuotaController struct {
	log                   logrus.FieldLogger
	maxPoliciesPerNS      int
	namespacePolicyCounts map[string]int
	mu                    sync.RWMutex
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	maxPerNamespace int,
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                   log,
		maxPoliciesPerNS:      maxPerNamespace,
		namespacePolicyCounts: make(map[string]int),
		ciliumNetworkPolicies: ciliumNetworkPolicies,
	}
}

// Run starts the controller's main event processing loop.
// It watches CiliumNetworkPolicy resources and tracks per-namespace counts.
func (p *PolicyQuotaController) Run(ctx context.Context) {
	p.log.Info("PolicyQuotaController started")
	defer p.log.Info("PolicyQuotaController stopped")

	events := p.ciliumNetworkPolicies.Events(ctx)
	for {
		select {
		case <-ctx.Done():
			return
		case event, ok := <-events:
			if !ok {
				return
			}

			switch event.Kind {
			case resource.Sync:
				p.log.Debug("CiliumNetworkPolicy resource synced")
				event.Done(nil)
			case resource.Upsert:
				p.handleUpsert(event.Object, event.Key)
				event.Done(nil)
			case resource.Delete:
				p.handleDelete(event.Object, event.Key)
				event.Done(nil)
			}
		}
	}
}

// handleUpsert processes an upsert event for a CiliumNetworkPolicy.
func (p *PolicyQuotaController) handleUpsert(policy *cilium_v2.CiliumNetworkPolicy, key resource.Key) {
	if policy == nil {
		return
	}

	ns := policy.Namespace
	p.mu.Lock()
	defer p.mu.Unlock()

	// Check if this is a new policy
	currentCount := p.namespacePolicyCounts[ns]
	p.namespacePolicyCounts[ns] = currentCount + 1

	p.log.WithFields(logrus.Fields{
		logfields.K8sNamespace: ns,
		"policyName":           policy.Name,
		"count":                p.namespacePolicyCounts[ns],
		"max":                  p.maxPoliciesPerNS,
	}).Debug("CiliumNetworkPolicy upserted")
}

// handleDelete processes a delete event for a CiliumNetworkPolicy.
func (p *PolicyQuotaController) handleDelete(policy *cilium_v2.CiliumNetworkPolicy, key resource.Key) {
	if policy == nil {
		return
	}

	ns := policy.Namespace
	p.mu.Lock()
	defer p.mu.Unlock()

	if count, ok := p.namespacePolicyCounts[ns]; ok && count > 0 {
		p.namespacePolicyCounts[ns] = count - 1
		if p.namespacePolicyCounts[ns] == 0 {
			delete(p.namespacePolicyCounts, ns)
		}
	}

	p.log.WithFields(logrus.Fields{
		logfields.K8sNamespace: ns,
		"policyName":           policy.Name,
		"count":                p.namespacePolicyCounts[ns],
	}).Debug("CiliumNetworkPolicy deleted")
}

// CheckQuota returns an error if the quota for the given namespace has been exceeded.
func (p *PolicyQuotaController) CheckQuota(namespace string) error {
	p.mu.RLock()
	defer p.mu.RUnlock()

	count := p.namespacePolicyCounts[namespace]
	if count >= p.maxPoliciesPerNS {
		return fmt.Errorf(
			"policy quota exceeded for namespace %q: current count %d, maximum allowed %d",
			namespace,
			count,
			p.maxPoliciesPerNS,
		)
	}
	return nil
}

