// fakeResource implements a minimal resource.Resource[T] for testing
type fakeResource struct {
	events chan resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

func (f *fakeResource) Events(ctx context.Context) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return f.events
}

func newFakeResource() *fakeResource {
	return &fakeResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 100),
	}
}

func TestPolicyQuotaController_CheckQuota(t *testing.T) {
	maxPolicies := 5
	fakeRes := newFakeResource()
	controller := NewPolicyQuotaController(maxPolicies, fakeRes)

	// Test CheckQuota when count is below limit
	err := controller.CheckQuota("default")
	assert.NoError(t, err, "should not exceed quota when count is 0")

	// Manually set counts to test quota checking
	controller.mu.Lock()
	controller.namespacePolicyCounts["default"] = 4
	controller.mu.Unlock()

	err = controller.CheckQuota("default")
	assert.NoError(t, err, "should not exceed quota when count is 4 and max is 5")

	// Set count to maximum
	controller.mu.Lock()
	controller.namespacePolicyCounts["default"] = 5
	controller.mu.Unlock()

	err = controller.CheckQuota("default")
	assert.Error(t, err, "should exceed quota when count equals max")
	assert.Contains(t, err.Error(), "policy quota exceeded")

	// Test with different namespace
	err = controller.CheckQuota("other-ns")
	assert.NoError(t, err, "should not exceed quota in different namespace")
}

func TestPolicyQuotaController_Run(t *testing.T) {
	maxPolicies := 3
	fakeRes := newFakeResource()
	controller := NewPolicyQuotaController(maxPolicies, fakeRes)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Start controller in a goroutine
	go controller.Run(ctx)

	// Give the controller time to start
	time.Sleep(10 * time.Millisecond)

	// Create test policies
	policy1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-1",
			Namespace: "test-ns",
		},
		Spec: &api.Rule{
			EndpointSelector: api.NewESFromLabels(),
		},
	}

	policy2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-2",
			Namespace: "test-ns",
		},
		Spec: &api.Rule{
			EndpointSelector: api.NewESFromLabels(),
		},
	}

	policy3 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-3",
			Namespace: "test-ns",
		},
		Spec: &api.Rule{
			EndpointSelector: api.NewESFromLabels(),
		},
	}

	// Send Sync event first
	syncEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind: resource.Sync,
	}
	syncEvent.Done_ = make(chan error, 1)
	fakeRes.events <- syncEvent

	// Wait for sync to be processed
	time.Sleep(10 * time.Millisecond)

	// Verify initial quota is OK
	err := controller.CheckQuota("test-ns")
	assert.NoError(t, err)

	// Send upsert event for policy 1
	key1 := resource.Key{Name: "test-policy-1", Namespace: "test-ns"}
	event1 := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Key:    key1,
		Object: policy1,
	}
	event1.Done_ = make(chan error, 1)
	fakeRes.events <- event1

	time.Sleep(10 * time.Millisecond)

	// Check count is 1
	controller.mu.RLock()
	assert.Equal(t, 1, controller.namespacePolicyCounts["test-ns"])
	controller.mu.RUnlock()

	// Send upsert event for policy 2
	key2 := resource.Key{Name: "test-policy-2", Namespace: "test-ns"}
	event2 := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Key:    key2,
		Object: policy2,
	}
	event2.Done_ = make(chan error, 1)
	fakeRes.events <- event2

	time.Sleep(10 * time.Millisecond)

	// Check count is 2
	controller.mu.RLock()
	assert.Equal(t, 2, controller.namespacePolicyCounts["test-ns"])
	controller.mu.RUnlock()

	// Send upsert event for policy 3
	key3 := resource.Key{Name: "test-policy-3", Namespace: "test-ns"}
	event3 := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Key:    key3,
		Object: policy3,
	}
	event3.Done_ = make(chan error, 1)
	fakeRes.events <- event3

	time.Sleep(10 * time.Millisecond)

	// Check count is 3
	controller.mu.RLock()
	assert.Equal(t, 3, controller.namespacePolicyCounts["test-ns"])
	controller.mu.RUnlock()

	// Verify quota is now exceeded
	err = controller.CheckQuota("test-ns")
	assert.Error(t, err, "should exceed quota when count equals max")

	// Send delete event for policy 1
	delEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Delete,
		Key:    key1,
		Object: policy1,
	}
	delEvent.Done_ = make(chan error, 1)
	fakeRes.events <- delEvent

	time.Sleep(10 * time.Millisecond)

	// Check count is 2 again
	controller.mu.RLock()
	assert.Equal(t, 2, controller.namespacePolicyCounts["test-ns"])
	controller.mu.RUnlock()

	// Verify quota is OK again
	err = controller.CheckQuota("test-ns")
	assert.NoError(t, err)
}

